var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님, 혹시 많이 화나셨나요?","JPN":"レジーナ様、もしや……怒っていますか？","ENG":"Are you angry, Miss Regina?","TWN":"蕾佳娜大人，您很生氣嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 제가 그런 표정을 짓고 있었어요?","JPN":"え？　私、そんな顔をしていましたか？","ENG":"Sorry? Did I look angry?","TWN":"什麼？我露出了那種表情嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 무척 심란해 보이셔서...... 저희가 괜한 이야기를 드린 걸까요?","JPN":"ええ。とても怖い顔をして……我々は何か余計なことを言いましたか？","ENG":"Yes. You looked very troubled. Was it too much for you to take in?","TWN":"是。因為您看起來很煩躁……是我們說了不該說的話嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 그렇진 않아요. 어머니에 대한 기억 탓이죠.","JPN":"いいえ、大丈夫ですわ。母に関する記憶のせいでしょう。","ENG":"No, it's okay. It's just these memories I have with my mother.","TWN":"不，沒有。是因為想起了有關母親的回憶吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고향을 떠난 뒤로 이상하리만치 깨끗하게 잊고 지냈는데...... 돌아오고 나서부터 드문드문 떠오르네요.","JPN":"故郷を離れてから、おかしなほどすっかり\\n忘れていましたが……帰って来てから時々思い出してしまって。","ENG":"I thought I lost them all while I was away from home, but I keep having these flashbacks.","TWN":"明明離開故鄉後，我就把這些事情忘得異常地乾淨……但自從回到這裡後，總是不時會想起來呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"정말이지, 싫어도 고향은 고향인가 봐요.","JPN":"本当に、嫌でも故郷は故郷みたいですわ。","ENG":"I guess home is home, no matter how hard I try to forget about it.","TWN":"真是的，就算討厭，故鄉還是故鄉呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 부인은 역대 학회장 중 가장 오랫동안 재임해 온 분이세요.","JPN":"マクレディー夫人は歴代学会長の中でも、最も在任期間の長い方でした。","ENG":"Mrs. MacCready served as the President for the longest time in the Society's history.","TWN":"麥克蕾蒂夫人是歷任學會長中，在任時間最長的一位。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"누구보다 가문과 학회를 아끼셨지만...... 시간이 흐르면서 그 마음이 잘못된 방향으로 엇나가 버렸죠.","JPN":"誰よりもマクレディー家と学会を大切にしていましたが……\\n時が経ち、その気持ちが誤った方向へ膨らんでしまったのです。","ENG":"She cherished her family and the Society more than anyone else, but her enthusiasm eventually led her down the wrong path.","TWN":"她比任何人都要珍惜家族和學會，但是……隨著時間的流逝，這份珍惜也漸漸偏向了錯誤的方向。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니를 변호해 주실 필요 없어요.","JPN":"お母様を擁護する必要はありません。","ENG":"You don't have to defend my mother.","TWN":"妳沒必要為母親辯護。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신에게는 미안한 짓이 되었지만...... 저는 영지를 떠나서 다행이었다고 생각해요.","JPN":"あなたには申し訳ありませんでしたが……私は領地を離れて正解だったと思っていますの。","ENG":"I feel sorry for what happened to you, but I'm glad that I left the estate.","TWN":"雖然這麼說不太對得起妳……但我仍然覺得自己離開這裡真是太好了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그대로 머물러 있었다면 어머니처럼 자랐거나, 그전에 죽었거나. 둘 중 하나였겠죠.","JPN":"そのまま留まっていれば、お母様のような人間に\\n育ったか、その前に死んだかのどちらかだったでしょう。","ENG":"If I had stayed, I would have either become just like my mother, or died before I did.","TWN":"如果我留在這裡，我應該就會長大成母親那樣的人，或是在那之前就死掉。只可能是這兩種結局吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하긴 목숨이 위태로운 건 지금도 마찬가지네요.","JPN":"まあ、命が危ういのは今も同じですけどね。","ENG":"But then, look at me. I'm back home, and death doesn't seem to be far anyway.","TWN":"說起來，生命受到威脅這點，現在也是一樣的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그럴 리는 없으니 걱정하지 마세요.","JPN":"そんなはずはありませんから、ご心配なく。","ENG":"You'll be fine, so don't worry.","TWN":"不會有這種事的，請不要擔心。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님은 차기 학회장이시잖아요. 계승식 전까지는 저희가 꼭 지켜 드릴게요.","JPN":"レジーナ様は次期学会長です。継承式までは我々が必ずお守りしますから。","ENG":"You're the next President of the Society. We'll make sure nothing happens to you before the succession ceremony.","TWN":"蕾佳娜大人是下任學會長啊。在繼承儀式結束前，我們一定會保護您的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말뿐이라도 고맙네요. 계승식만 운운하지 않았으면 더 고마웠을 텐데요.","JPN":"言葉だけでもありがたいですわ。継承式の話さえしなければ、もっとありがたかったと思いますが。","ENG":"Thank you, really. It would have been much nicer if you left the succession ceremony part out.","TWN":"就算妳只是說說，我也很感謝妳。而如果妳沒提到繼承儀式，我會更感謝妳的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"거기 화기애애하게 노닥거리는 두 사람! 여기야!","JPN":"そこの仲良くおしゃべりしてるお二人さん！　ここだよ！","ENG":"Hey, chatterboxes! Over here!","TWN":"在那邊和樂融融，打情罵俏的那兩個！在這裡！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니는 찾았나요?","JPN":"母は見つかりましたか？","ENG":"Did you find my mother?","TWN":"找到母親了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};